"""
Docker service for AgentCube CLI.

Handles Docker image build, push, and removal operations.

Copyright 2025 The Volcano Authors.
Licensed under the Apache License, Version 2.0.
"""

import logging
import time
from pathlib import Path
from typing import Optional, Dict

try:
    import docker
    from docker.errors import DockerException, ImageNotFound
    DOCKER_AVAILABLE = True
except ImportError:
    DOCKER_AVAILABLE = False

logger = logging.getLogger(__name__)


class DockerService:
    """Service for Docker operations."""

    def __init__(self, verbose: bool = False) -> None:
        self.verbose = verbose
        self.logger = logging.getLogger(__name__)
        self._client = None

    def _get_client(self):
        """Get or create Docker client."""
        if not DOCKER_AVAILABLE:
            raise RuntimeError("Docker SDK is not installed")

        if self._client is None:
            try:
                self._client = docker.from_env()
            except DockerException as e:
                raise RuntimeError(f"Docker is not available or not running: {e}")

        return self._client

    def check_docker_available(self) -> bool:
        """Check if Docker is available."""
        if not DOCKER_AVAILABLE:
            return False

        try:
            client = self._get_client()
            client.ping()
            return True
        except Exception:
            return False

    def build_image(
        self,
        dockerfile_path: Path,
        context_path: Path,
        image_name: str,
        tag: str = "latest",
        build_args: Optional[Dict[str, str]] = None,
    ) -> Dict[str, str]:
        """Build a Docker image."""
        client = self._get_client()

        if not dockerfile_path.exists():
            raise FileNotFoundError(f"Dockerfile not found: {dockerfile_path}")

        if not context_path.exists():
            raise FileNotFoundError(f"Context path not found: {context_path}")

        full_image_name = f"{image_name}:{tag}"
        self.logger.info(f"Building image: {full_image_name}")

        build_args = build_args or {}
        start_time = time.time()

        try:
            # Build the image
            image, build_logs = client.images.build(
                path=str(context_path),
                dockerfile=str(dockerfile_path.relative_to(context_path)),
                tag=full_image_name,
                buildargs=build_args,
                rm=True,
            )

            build_time = time.time() - start_time

            # Get image info
            image_info = self._get_image_info(full_image_name)

            return {
                "image_name": full_image_name,
                "image_id": image.id,
                "image_size": image_info.get("size", "unknown"),
                "build_time": f"{build_time:.2f}s",
            }

        except Exception as e:
            raise RuntimeError(f"Failed to build image: {e}")

    def get_image_info(self, image_name: str) -> Dict[str, str]:
        """Get information about a Docker image."""
        return self._get_image_info(image_name)

    def _get_image_info(self, image_name: str) -> Dict[str, str]:
        """Internal method to get image information."""
        client = self._get_client()

        try:
            image = client.images.get(image_name)
            size_bytes = image.attrs.get("Size", 0)

            return {
                "id": image.id,
                "size": self._format_size(size_bytes),
                "size_bytes": str(size_bytes),
                "created": image.attrs.get("Created", "unknown"),
            }
        except ImageNotFound:
            return {"error": "Image not found"}
        except Exception as e:
            return {"error": str(e)}

    def _format_size(self, size_bytes: int) -> str:
        """Format size in human-readable format."""
        for unit in ["B", "KB", "MB", "GB"]:
            if size_bytes < 1024:
                return f"{size_bytes:.2f} {unit}"
            size_bytes /= 1024
        return f"{size_bytes:.2f} TB"

    def push_image(
        self,
        image_name: str,
        registry_url: Optional[str] = None,
        username: Optional[str] = None,
        password: Optional[str] = None,
    ) -> Dict[str, str]:
        """Push a Docker image to a registry."""
        client = self._get_client()

        start_time = time.time()

        try:
            # Login if credentials provided
            if username and password:
                self._docker_login_sdk(registry_url, username, password)

            # Tag image if registry URL provided
            if registry_url:
                target_image = f"{registry_url.rstrip('/')}/{image_name}"
                self._tag_image_sdk(image_name, target_image)
            else:
                target_image = image_name

            self.logger.info(f"Pushing image: {target_image}")

            # Push the image
            push_logs = client.images.push(target_image, stream=True, decode=True)

            # Consume logs
            for log in push_logs:
                if self.verbose and "status" in log:
                    self.logger.debug(f"Push status: {log['status']}")

            push_time = time.time() - start_time

            return {
                "pushed_image": target_image,
                "push_time": f"{push_time:.2f}s",
            }

        except Exception as e:
            raise RuntimeError(f"Failed to push image: {e}")

    def _docker_login_sdk(
        self,
        registry: Optional[str],
        username: str,
        password: str,
    ) -> None:
        """Login to Docker registry."""
        client = self._get_client()

        self.logger.info(f"Logging in to registry: {registry or 'Docker Hub'}")

        try:
            client.login(
                username=username,
                password=password,
                registry=registry,
            )
        except Exception as e:
            raise RuntimeError(f"Docker login failed: {e}")

    def _tag_image_sdk(self, source_image: str, target_image: str) -> None:
        """Tag a Docker image."""
        client = self._get_client()

        try:
            image = client.images.get(source_image)
            image.tag(target_image)
            self.logger.debug(f"Tagged {source_image} as {target_image}")
        except Exception as e:
            raise RuntimeError(f"Failed to tag image: {e}")

    def remove_image(self, image_name: str) -> bool:
        """Remove a Docker image."""
        client = self._get_client()

        try:
            client.images.remove(image_name, force=True)
            self.logger.info(f"Removed image: {image_name}")
            return True
        except ImageNotFound:
            self.logger.warning(f"Image not found for removal: {image_name}")
            return False
        except Exception as e:
            self.logger.warning(f"Failed to remove image {image_name}: {e}")
            return False

"""
Kubernetes provider for AgentCube CLI.

Handles Deployment and Service creation for standard Kubernetes.

Copyright 2025 The Volcano Authors.
Licensed under the Apache License, Version 2.0.
"""

import logging
import time
from typing import Optional, Dict, Any

try:
    from kubernetes import client, config, utils
    from kubernetes.client import ApiException
    K8S_AVAILABLE = True
except ImportError:
    K8S_AVAILABLE = False

logger = logging.getLogger(__name__)


class KubernetesProvider:
    """Provider for standard Kubernetes deployments."""

    def __init__(
        self,
        namespace: str = "default",
        verbose: bool = False,
        kubeconfig: Optional[str] = None,
    ) -> None:
        self.namespace = namespace
        self.verbose = verbose
        self.logger = logging.getLogger(__name__)
        self.kubeconfig = kubeconfig

        if K8S_AVAILABLE:
            self._init_k8s_client()
        else:
            self.apps_v1 = None
            self.core_v1 = None

    def _init_k8s_client(self) -> None:
        """Initialize Kubernetes client."""
        try:
            if self.kubeconfig:
                config.load_kube_config(config_file=self.kubeconfig)
            else:
                config.load_kube_config()
        except Exception:
            try:
                config.load_incluster_config()
            except Exception:
                self.logger.warning("Failed to load Kubernetes config")

        self.apps_v1 = client.AppsV1Api()
        self.core_v1 = client.CoreV1Api()

    def _ensure_namespace(self) -> None:
        """Ensure namespace exists."""
        if not K8S_AVAILABLE:
            raise RuntimeError("Kubernetes client is not installed")

        try:
            self.core_v1.read_namespace(self.namespace)
        except ApiException as e:
            if e.status == 404:
                self.logger.info(f"Creating namespace: {self.namespace}")
                namespace_body = client.V1Namespace(
                    metadata=client.V1ObjectMeta(name=self.namespace)
                )
                self.core_v1.create_namespace(namespace_body)
            else:
                raise

    def deploy_agent(
        self,
        agent_name: str,
        image_url: str,
        port: int,
        entrypoint: Optional[str] = None,
        replicas: int = 1,
        node_port: Optional[int] = None,
        env_vars: Optional[Dict[str, str]] = None,
    ) -> Dict[str, Any]:
        """Deploy agent to Kubernetes."""
        if not K8S_AVAILABLE:
            raise RuntimeError("Kubernetes client is not installed")

        self._ensure_namespace()

        sanitized_name = self._sanitize_name(agent_name)

        # Create deployment
        deployment_result = self._create_deployment(
            name=sanitized_name,
            image_url=image_url,
            port=port,
            entrypoint=entrypoint,
            replicas=replicas,
            env_vars=env_vars,
        )

        # Create service
        service_result = self._create_service(
            name=sanitized_name,
            port=port,
            node_port=node_port,
        )

        return {
            "deployment_name": deployment_result["name"],
            "service_name": service_result["name"],
            "namespace": self.namespace,
            "replicas": replicas,
            "container_port": port,
            "node_port": service_result.get("node_port"),
            "service_url": service_result.get("url"),
        }

    def _create_deployment(
        self,
        name: str,
        image_url: str,
        port: int,
        entrypoint: Optional[str],
        replicas: int,
        env_vars: Optional[Dict[str, str]],
    ) -> Dict[str, Any]:
        """Create Kubernetes Deployment."""
        env_list = []
        if env_vars:
            for key, value in env_vars.items():
                env_list.append(client.V1EnvVar(name=key, value=value))

        # Container command
        command = None
        args = None
        if entrypoint:
            parts = entrypoint.split()
            if parts:
                command = [parts[0]]
                args = parts[1:] if len(parts) > 1 else None

        container = client.V1Container(
            name=name,
            image=image_url,
            ports=[client.V1ContainerPort(container_port=port)],
            env=env_list,
            command=command,
            args=args,
        )

        template = client.V1PodTemplateSpec(
            metadata=client.V1ObjectMeta(labels={"app": name}),
            spec=client.V1PodSpec(containers=[container]),
        )

        spec = client.V1DeploymentSpec(
            replicas=replicas,
            selector={"matchLabels": {"app": name}},
            template=template,
        )

        deployment = client.V1Deployment(
            api_version="apps/v1",
            kind="Deployment",
            metadata=client.V1ObjectMeta(name=name),
            spec=spec,
        )

        try:
            # Try to create
            self.apps_v1.create_namespaced_deployment(
                namespace=self.namespace,
                body=deployment,
            )
            self.logger.info(f"Created deployment: {name}")
        except ApiException as e:
            if e.status == 409:
                # Already exists, update
                self.apps_v1.replace_namespaced_deployment(
                    name=name,
                    namespace=self.namespace,
                    body=deployment,
                )
                self.logger.info(f"Updated deployment: {name}")
            else:
                raise

        return {"name": name}

    def _create_service(
        self,
        name: str,
        port: int,
        node_port: Optional[int],
    ) -> Dict[str, Any]:
        """Create Kubernetes Service."""
        service_type = "NodePort" if node_port else "ClusterIP"

        service_port = client.V1ServicePort(
            port=port,
            target_port=port,
        )

        if node_port:
            service_port.node_port = node_port

        service = client.V1Service(
            api_version="v1",
            kind="Service",
            metadata=client.V1ObjectMeta(name=name),
            spec=client.V1ServiceSpec(
                selector={"app": name},
                ports=[service_port],
                type=service_type,
            ),
        )

        try:
            # Try to create
            result = self.core_v1.create_namespaced_service(
                namespace=self.namespace,
                body=service,
            )
            self.logger.info(f"Created service: {name}")
        except ApiException as e:
            if e.status == 409:
                # Already exists, update
                result = self.core_v1.replace_namespaced_service(
                    name=name,
                    namespace=self.namespace,
                    body=service,
                )
                self.logger.info(f"Updated service: {name}")
            else:
                raise

        # Get assigned node port
        actual_node_port = node_port
        url = None
        if result.spec.ports:
            actual_node_port = result.spec.ports[0].node_port
            if actual_node_port:
                url = f"http://localhost:{actual_node_port}"

        return {
            "name": name,
            "node_port": actual_node_port,
            "url": url,
        }

    def wait_for_deployment_ready(self, name: str, timeout: int = 120) -> None:
        """Wait for deployment to be ready."""
        if not K8S_AVAILABLE:
            raise RuntimeError("Kubernetes client is not installed")

        start_time = time.time()

        while time.time() - start_time < timeout:
            try:
                deployment = self.apps_v1.read_namespaced_deployment(
                    name=name,
                    namespace=self.namespace,
                )

                if deployment.status.ready_replicas == deployment.spec.replicas:
                    self.logger.info(f"Deployment {name} is ready")
                    return

                self.logger.debug(
                    f"Waiting for deployment {name}: "
                    f"{deployment.status.ready_replicas or 0}/{deployment.spec.replicas} ready"
                )
            except ApiException as e:
                if e.status != 404:
                    raise

            time.sleep(2)

        raise TimeoutError(f"Deployment {name} did not become ready within {timeout}s")

    def get_agent_status(self, agent_name: str) -> Dict[str, Any]:
        """Get agent status from Kubernetes."""
        if not K8S_AVAILABLE:
            raise RuntimeError("Kubernetes client is not installed")

        sanitized_name = self._sanitize_name(agent_name)

        try:
            deployment = self.apps_v1.read_namespaced_deployment(
                name=sanitized_name,
                namespace=self.namespace,
            )

            return {
                "status": "deployed",
                "deployment_name": sanitized_name,
                "namespace": self.namespace,
                "replicas": deployment.spec.replicas,
                "ready_replicas": deployment.status.ready_replicas or 0,
            }
        except ApiException as e:
            if e.status == 404:
                return {
                    "status": "not_found_in_k8s",
                    "deployment_name": sanitized_name,
                    "namespace": self.namespace,
                }
            raise

    def delete_agent(self, agent_name: str) -> Dict[str, Any]:
        """Delete agent from Kubernetes."""
        if not K8S_AVAILABLE:
            raise RuntimeError("Kubernetes client is not installed")

        sanitized_name = self._sanitize_name(agent_name)

        # Delete service (ignore 404)
        try:
            self.core_v1.delete_namespaced_service(
                name=sanitized_name,
                namespace=self.namespace,
            )
            self.logger.info(f"Deleted service: {sanitized_name}")
        except ApiException as e:
            if e.status != 404:
                raise

        # Delete deployment (ignore 404)
        try:
            self.apps_v1.delete_namespaced_deployment(
                name=sanitized_name,
                namespace=self.namespace,
            )
            self.logger.info(f"Deleted deployment: {sanitized_name}")
        except ApiException as e:
            if e.status != 404:
                raise

        return {
            "status": "deleted",
            "deployment_name": sanitized_name,
            "namespace": self.namespace,
        }

    def _sanitize_name(self, name: str) -> str:
        """Sanitize name for Kubernetes resources."""
        # Replace invalid characters with '-'
        sanitized = "".join(c if c.isalnum() else "-" for c in name.lower())
        # Remove leading/trailing hyphens
        sanitized = sanitized.strip("-")
        # Limit length
        if len(sanitized) > 63:
            sanitized = sanitized[:63].rsplit("-", 1)[0]
        return sanitized or "agent"

"""
AgentCube provider for AgentCube CLI.

Handles AgentRuntime CR creation for AgentCube.

Copyright 2025 The Volcano Authors.
Licensed under the Apache License, Version 2.0.
"""

import logging
from typing import Optional, Dict, Any

try:
    from kubernetes import client, config
    from kubernetes.client import ApiException
    K8S_AVAILABLE = True
except ImportError:
    K8S_AVAILABLE = False

logger = logging.getLogger(__name__)


class AgentCubeProvider:
    """Provider for AgentCube AgentRuntime CR deployments."""

    CR_GROUP = "runtime.agentcube.volcano.sh"
    CR_VERSION = "v1alpha1"
    CR_PLURAL = "agentruntimes"

    def __init__(
        self,
        namespace: str = "default",
        verbose: bool = False,
        kubeconfig: Optional[str] = None,
    ) -> None:
        self.namespace = namespace
        self.verbose = verbose
        self.logger = logging.getLogger(__name__)
        self.kubeconfig = kubeconfig

        if K8S_AVAILABLE:
            self._init_k8s_client()
        else:
            self.custom_api = None

    def _init_k8s_client(self) -> None:
        """Initialize Kubernetes client."""
        try:
            if self.kubeconfig:
                config.load_kube_config(config_file=self.kubeconfig)
            else:
                config.load_kube_config()
        except Exception:
            try:
                config.load_incluster_config()
            except Exception:
                self.logger.warning("Failed to load Kubernetes config")

        self.custom_api = client.CustomObjectsApi()

    def _ensure_namespace(self) -> None:
        """Ensure namespace exists."""
        if not K8S_AVAILABLE:
            raise RuntimeError("Kubernetes client is not installed")

        core_v1 = client.CoreV1Api()
        try:
            core_v1.read_namespace(self.namespace)
        except ApiException as e:
            if e.status == 404:
                self.logger.info(f"Creating namespace: {self.namespace}")
                namespace_body = client.V1Namespace(
                    metadata=client.V1ObjectMeta(name=self.namespace)
                )
                core_v1.create_namespace(namespace_body)
            else:
                raise

    def deploy_agent_runtime(
        self,
        agent_name: str,
        image_url: str,
        port: int,
        entrypoint: Optional[str] = None,
        env_vars: Optional[Dict[str, str]] = None,
        workload_manager_url: Optional[str] = None,
        router_url: Optional[str] = None,
        readiness_probe_path: Optional[str] = None,
        readiness_probe_port: Optional[int] = None,
    ) -> Dict[str, Any]:
        """Deploy AgentRuntime CR to Kubernetes."""
        if not K8S_AVAILABLE:
            raise RuntimeError("Kubernetes client is not installed")

        self._ensure_namespace()

        sanitized_name = self._sanitize_name(agent_name)

        # Prepare environment variables
        env = env_vars or {}

        # Add required URLs if not present
        if workload_manager_url and "WORKLOAD_MANAGER_URL" not in env:
            env["WORKLOAD_MANAGER_URL"] = workload_manager_url
        if router_url and "ROUTER_URL" not in env:
            env["ROUTER_URL"] = router_url

        # Build CR spec
        spec = {
            "image": image_url,
            "port": port,
            "sessionTimeout": "15m",
            "maxSessionDuration": "8h",
            "envVars": env,
            "imagePullSecrets": [{"name": "default-secret"}],
        }

        if entrypoint:
            spec["entrypoint"] = entrypoint

        if readiness_probe_path:
            spec["readinessProbe"] = {
                "path": readiness_probe_path,
                "port": readiness_probe_port or port,
            }

        cr = {
            "apiVersion": f"{self.CR_GROUP}/{self.CR_VERSION}",
            "kind": "AgentRuntime",
            "metadata": {
                "name": sanitized_name,
                "namespace": self.namespace,
            },
            "spec": spec,
        }

        try:
            # Try to create
            result = self.custom_api.create_namespaced_custom_object(
                group=self.CR_GROUP,
                version=self.CR_VERSION,
                namespace=self.namespace,
                plural=self.CR_PLURAL,
                body=cr,
            )
            self.logger.info(f"Created AgentRuntime CR: {sanitized_name}")
        except ApiException as e:
            if e.status == 409:
                # Already exists, update
                result = self.custom_api.replace_namespaced_custom_object(
                    group=self.CR_GROUP,
                    version=self.CR_VERSION,
                    namespace=self.namespace,
                    plural=self.CR_PLURAL,
                    name=sanitized_name,
                    body=cr,
                )
                self.logger.info(f"Updated AgentRuntime CR: {sanitized_name}")
            else:
                raise

        return {
            "cr_name": sanitized_name,
            "namespace": self.namespace,
            "status": "created",
        }

    def get_agent_runtime(self, name: str, namespace: str) -> Optional[Dict[str, Any]]:
        """Get AgentRuntime CR from Kubernetes."""
        if not K8S_AVAILABLE:
            raise RuntimeError("Kubernetes client is not installed")

        sanitized_name = self._sanitize_name(name)

        try:
            result = self.custom_api.get_namespaced_custom_object(
                group=self.CR_GROUP,
                version=self.CR_VERSION,
                namespace=namespace,
                plural=self.CR_PLURAL,
                name=sanitized_name,
            )
            return result
        except ApiException as e:
            if e.status == 404:
                return None
            raise

    def _sanitize_name(self, name: str) -> str:
        """Sanitize name for Kubernetes resources."""
        # Replace invalid characters with '-'
        sanitized = "".join(c if c.isalnum() else "-" for c in name.lower())
        # Remove leading/trailing hyphens
        sanitized = sanitized.strip("-")
        # Limit length
        if len(sanitized) > 63:
            sanitized = sanitized[:63].rsplit("-", 1)[0]
        return sanitized or "agent"
